script.text:

function init$StocktakingAdjustment$(f){
  if (f._action != 'View') f._setReadOnly(f.getItem('ma_kho'), f._action == 'Edit' && !f.getItemValue('dv_yn'));
  var g = f.grid;
  f.setItemValue('stt_rec', g._voucherID);
  if (f._action == 'New') f.setReferenceKeyFilter('ma_kho');
  else if (f._action == 'Edit') {
    if (!f.getItemValue('dv_yn')) f.getItem('ma_vt').focus();
  }
  set$Voucher$ReferenceKeyFilter$UOM(f);
}
function load$StocktakingAdjustment$(f) {f.add_onResponseComplete(on$StocktakingAdjustment$ResponseComplete);}
function close$PhysicalCountQtyUpdate$(f) {try {f.remove_onResponseComplete(on$StocktakingAdjustment$ResponseComplete);} catch (ex) {}}
function on$StocktakingAdjustment$ResponseComplete(f, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Item':
      f.setItemControlBehavior('dvt', result[0].Value, null, false);
      f.setItemValues('ten_dvt%l, nhieu_dvt', [result[1].Value, result[2].Value]);
      set$Voucher$ReferenceKeyFilter$UOM(f);
      f.setReferenceKeyFilter('ma_lo');
      break;
    default:
      break;
  }
}
function change$StocktakingAdjustment$Item$(o) {
  var f = o.parentForm, name = o.field.Name;
  switch (name) {
    case 'ma_vt':
      f.request('Item', 'Item', ['ma_vt'], o);
      break;
    case 'ma_kho':  
      f.setReferenceKeyFilter('ma_vi_tri');
      break;
    case 'so_luong1':
    case 'so_luong2':
    case 'so_luong3':
      f.executeExpression(['[so_luong]:= ([so_luong1] + [so_luong2] + [so_luong3])']);
      f.live(f.getItem('so_luong'));
      break;
    default:
      break;
  }
}
function set$Voucher$ReferenceKeyFilter$UOM(f) {
  var v = f.getItemValue('nhieu_dvt');
  if(v) f.setReferenceKeyFilter('dvt');
  f._setReadOnly(f.getItem('dvt'), !v);
}
